const data = $input.item.json;
const tournaments = Array.isArray(data) ? data : data.tournaments || data.data || [];
return tournaments.map(t => ({ json: t }));

const data = $input.item.json;
const portfolios = Array.isArray(data) ? data : data.portfolios || data.participants || [];

// Calculate Sharpe ratio for each participant
const ranked = portfolios.map(p => {
  const returns = p.dailyReturns || [];
  const avgReturn = returns.length > 0 ? returns.reduce((a, b) => a + b, 0) / returns.length : 0;
  const variance = returns.length > 1 
    ? returns.reduce((sum, r) => sum + Math.pow(r - avgReturn, 2), 0) / (returns.length - 1) 
    : 0;
  const stdDev = Math.sqrt(variance);
  const sharpe = stdDev > 0 ? (avgReturn * 252) / (stdDev * Math.sqrt(252)) : 0;
  const totalReturn = p.totalValue && p.startingValue 
    ? ((p.totalValue - p.startingValue) / p.startingValue) * 100 
    : 0;
  const maxDrawdown = p.maxDrawdown || 0;

  return {
    userId: p.userId,
    username: p.username || p.userId,
    totalValue: p.totalValue,
    totalReturnPct: totalReturn,
    sharpeRatio: sharpe,
    maxDrawdown,
    tradeCount: p.tradeCount || 0
  };
}).sort((a, b) => b.sharpeRatio - a.sharpeRatio);

// Add rank
ranked.forEach((p, i) => { p.rank = i + 1; });

const medalMap = { 1: '🥇', 2: '🥈', 3: '🥉' };
const leaderboardText = ranked.slice(0, 10).map(p => 
  `${medalMap[p.rank] || `${p.rank}.`} **${p.username}** — Sharpe: ${p.sharpeRatio.toFixed(3)} | Return: ${p.totalReturnPct.toFixed(2)}%`
).join('\n');

return [{ json: { rankings: ranked, leaderboardText, tournamentId: data.tournamentId || 'tournament', updatedAt: new Date().toISOString() } }];

